// source: ui-click-sound-script
(function(){
  const UI_BUTTON_IDS = new Set([
    'begin',
    'muteTitle',
    'usernameBtn',
    'extrasBtn',
    'showInstructions',
    'showControls',
    'leaderboardBtn'
  ]);

  let ctx = null;
  let buffer = null;
  let decoding = false;
  const MP3_B64 = "";

  function getCtx(){
    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC) return null;
    if (!ctx) ctx = new AC();
    if (ctx.state === 'suspended') ctx.resume().catch(function(){});
    return ctx;
  }

  function b64ToArrayBuffer(b64){
    const binary = atob(b64);
    const len = binary.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = binary.charCodeAt(i);
    return bytes.buffer;
  }

  function isSoundMutedForMenuClick(){
    try {
      if (window.__undeadSoundMuted === true) return true;
      return (localStorage.getItem("undeadNightfallSoundMuted") || localStorage.getItem("undeadNightfallMusicMuted")) === "1";
    } catch(e) {
      return window.__undeadSoundMuted === true;
    }
  }


  async function decodeMp3(){
    const ac = getCtx();
    if (!ac || buffer || decoding || !MP3_B64) return;
    decoding = true;
    try {
      const arr = b64ToArrayBuffer(MP3_B64);
      buffer = await ac.decodeAudioData(arr.slice(0));
    } catch(e) {
      buffer = null;
    }
    decoding = false;
  }

  function isTitleScreenVisible(){
    const start = document.getElementById('start');
    if (!start) return false;
    const style = window.getComputedStyle(start);
    return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0' && !start.classList.contains('hidden');
  }

  function isMenuButtonEvent(ev){
    // Keep this sound strictly on the title/menu overlay. Gameplay controls
    // such as Sword, Fireball, and Chain Lightning must never trigger it.
    if (isSoundMutedForMenuClick() || !isTitleScreenVisible()) return false;

    let el = ev.target;
    const start = document.getElementById('start');
    while (el && el !== document) {
      if (start && !start.contains(el)) return false;
      if (el.id && UI_BUTTON_IDS.has(el.id)) return true;
      el = el.parentNode;
    }
    return false;
  }

  function playSynthFallback(){
    if (isSoundMutedForMenuClick()) return;
    const ac = getCtx();
    if (!ac) return;
    const now = ac.currentTime;

    const master = ac.createGain();
    master.gain.value = 0.65;
    master.connect(ac.destination);

    const osc1 = ac.createOscillator();
    const gain1 = ac.createGain();
    osc1.type = 'triangle';
    osc1.frequency.setValueAtTime(180, now);
    osc1.frequency.exponentialRampToValueAtTime(75, now + 0.09);
    gain1.gain.setValueAtTime(0.0001, now);
    gain1.gain.exponentialRampToValueAtTime(0.65, now + 0.006);
    gain1.gain.exponentialRampToValueAtTime(0.0001, now + 0.13);
    osc1.connect(gain1); gain1.connect(master);

    const osc2 = ac.createOscillator();
    const gain2 = ac.createGain();
    osc2.type = 'square';
    osc2.frequency.setValueAtTime(980, now);
    osc2.frequency.exponentialRampToValueAtTime(420, now + 0.055);
    gain2.gain.setValueAtTime(0.0001, now);
    gain2.gain.exponentialRampToValueAtTime(0.18, now + 0.003);
    gain2.gain.exponentialRampToValueAtTime(0.0001, now + 0.07);
    osc2.connect(gain2); gain2.connect(master);

    osc1.start(now); osc1.stop(now + 0.14);
    osc2.start(now); osc2.stop(now + 0.08);
  }

  async function playClick(){
    if (isSoundMutedForMenuClick()) return;
    const ac = getCtx();
    if (!ac) return;

    if (!buffer && !decoding && MP3_B64) await decodeMp3();

    if (buffer) {
      try {
        const source = ac.createBufferSource();
        const gain = ac.createGain();
        gain.gain.value = 1.0;
        source.buffer = buffer;
        source.connect(gain);
        gain.connect(ac.destination);
        source.start(0);
        return;
      } catch(e) {}
    }

    playSynthFallback();
  }

  function handle(ev){
    if (!isMenuButtonEvent(ev)) return;
    playClick();
  }

  // Capture phase so existing button handlers cannot prevent the sound.
  document.addEventListener('pointerdown', handle, {capture:true, passive:true});
  document.addEventListener('touchstart', handle, {capture:true, passive:true});
  document.addEventListener('mousedown', handle, {capture:true, passive:true});

  document.addEventListener('pointerdown', function(ev){
    if (isMenuButtonEvent(ev)) decodeMp3();
  }, {capture:true, passive:true});

  document.addEventListener('touchstart', function(ev){
    if (isMenuButtonEvent(ev)) decodeMp3();
  }, {capture:true, passive:true});
})();
